//! Basic I/O operations with NIfTI files

use neuroim::{read_nifti, write_nifti, read_nifti_header, NeuroVol};
use neuroim::error::Result;

fn main() -> Result<()> {
    // Read a NIfTI file
    println!("Reading NIfTI file...");
    let volume = read_nifti::<f32>("data/brain.nii.gz")?;

    // Print basic information
    println!("Volume dimensions: {:?}", volume.dim());
    println!("Voxel spacing: {:?}", volume.spacing());
    println!("Data type: f32");

    // Access voxel values
    let center_x = volume.dim()[0] / 2;
    let center_y = volume.dim()[1] / 2;
    let center_z = volume.dim()[2] / 2;

    if let Some(value) = volume.get_at(center_x, center_y, center_z) {
        println!("Center voxel value: {}", value);
    }

    // Read just the header for metadata
    println!("\nReading header only...");
    let header = read_nifti_header("data/brain.nii.gz")?;
    println!("Description: {:?}", header.descrip);
    println!("Intent: {:?}", header.intent_name);

    // Modify the volume
    println!("\nCreating a modified copy...");
    let mut dense = volume.as_dense()?;

    // Set a region to zero (e.g., for masking)
    for x in 40..50 {
        for y in 40..50 {
            for z in 40..50 {
                dense.set_at(x, y, z, 0.0)?;
            }
        }
    }

    // Write the modified volume
    println!("Writing modified volume...");
    write_nifti("data/brain_modified.nii.gz", &dense)?;

    println!("Done!");

    Ok(())
}

