//! Spatial filtering examples

use neuroim::{
    read_nifti, write_nifti, 
    gaussian_blur, bilateral_filter, guided_filter,
    gaussian_kernel, spherical_kernel, box_kernel,
    NeuroVol, DenseNeuroVol
};
use neuroim::error::Result;

fn main() -> Result<()> {
    // Read input volume
    println!("Reading input volume...");
    let volume = read_nifti::<f32>("data/brain.nii.gz")?;

    // Example 1: Gaussian smoothing
    println!("\n1. Gaussian smoothing (FWHM = 4mm)...");
    let gauss_kernel = gaussian_kernel(4.0)?;
    let gaussian_smoothed = gaussian_blur(&volume, &gauss_kernel)?;
    write_nifti("output/brain_gaussian_4mm.nii.gz", &gaussian_smoothed)?;

    // Example 2: Box filter (mean filter)
    println!("\n2. Box filter (3x3x3)...");
    let box_kern = box_kernel(3)?;
    let box_filtered = gaussian_blur(&volume, &box_kern)?;
    write_nifti("output/brain_box_3.nii.gz", &box_filtered)?;

    // Example 3: Spherical kernel
    println!("\n3. Spherical kernel (radius = 2 voxels)...");
    let sphere_kern = spherical_kernel(2.0)?;
    let sphere_filtered = gaussian_blur(&volume, &sphere_kern)?;
    write_nifti("output/brain_sphere_2.nii.gz", &sphere_filtered)?;

    // Example 4: Bilateral filter (edge-preserving)
    println!("\n4. Bilateral filter (edge-preserving)...");
    let spatial_sigma = 3.0;  // Spatial extent
    let range_sigma = 20.0;   // Intensity similarity
    let bilateral_filtered = bilateral_filter(&volume, spatial_sigma, range_sigma)?;
    write_nifti("output/brain_bilateral.nii.gz", &bilateral_filtered)?;

    // Example 5: Guided filter
    println!("\n5. Guided filter (using same image as guide)...");
    let radius = 5.0;
    let epsilon = 0.01;
    let guided_filtered = guided_filter(&volume, &volume, radius, epsilon)?;
    write_nifti("output/brain_guided.nii.gz", &guided_filtered)?;

    // Example 6: Multi-scale smoothing
    println!("\n6. Multi-scale smoothing...");
    let scales = vec![2.0, 4.0, 8.0];
    for scale in scales {
        let kernel = gaussian_kernel(scale)?;
        let smoothed = gaussian_blur(&volume, &kernel)?;
        let filename = format!("output/brain_scale_{:.0}mm.nii.gz", scale);
        write_nifti(&filename, &smoothed)?;
        println!("   Saved {}", filename);
    }

    println!("\nFiltering complete!");

    Ok(())
}

