//! ROI analysis examples

use neuroim::{
    read_nifti, NeuroVol, LogicalNeuroVol,
    spherical_roi, cuboid_roi, square_roi,
    ROI, ROIVol, ROICoords
};
use neuroim::error::Result;
use ndarray::Array3;

fn main() -> Result<()> {
    // Read brain volume and mask
    println!("Reading brain volume...");
    let brain = read_nifti::<f32>("data/brain.nii.gz")?;

    // Create a brain mask (simple thresholding)
    println!("Creating brain mask...");
    let threshold = 100.0;
    let mask_data = brain.as_dense()?.data.mapv(|v| v > threshold);
    let mask = LogicalNeuroVol::new(mask_data, brain.space().clone())?;

    // Example 1: Spherical ROI
    println!("\n1. Extracting spherical ROI...");
    let center = [45, 54, 45]; // MNI coordinates near motor cortex
    let radius = 10.0; // 10mm radius
    let sphere_roi = spherical_roi::<f32>(&mask, &center, radius, None, true)?;

    println!("   Sphere contains {} voxels", sphere_roi.size());

    // Extract values from the brain volume at ROI locations
    let roi_values: Vec<f32> = sphere_roi.coords.indices()
        .iter()
        .filter_map(|&idx| {
            let dense = brain.as_dense().ok()?;
            dense.data.as_slice().unwrap().get(idx).copied()
        })
        .collect();

    if !roi_values.is_empty() {
        let mean_value: f32 = roi_values.iter().sum::<f32>() / roi_values.len() as f32;
        println!("   Mean value in sphere: {:.2}", mean_value);
    }

    // Example 2: Cubic ROI
    println!("\n2. Extracting cubic ROI...");
    let cube_roi = cuboid_roi(&mask, (45, 54, 45), (7, 7, 7))?;
    println!("   Cube contains {} voxels", cube_roi.size());

    // Example 3: Square ROI in different planes
    println!("\n3. Extracting 2D square ROIs...");
    let planes = vec!["xy", "xz", "yz"];
    for plane in planes {
        let square = square_roi(&mask, (45, 54, 45), 5, plane)?;
        println!("   Square in {} plane: {} voxels", plane, square.size());
    }

    // Example 4: Multiple ROIs for connectivity analysis
    println!("\n4. Creating seed regions for connectivity...");
    let seed_centers = vec![
        [30, 40, 50], // Left hemisphere
        [60, 40, 50], // Right hemisphere
        [45, 60, 60], // Superior region
        [45, 30, 40], // Inferior region
    ];

    let mut seed_rois = Vec::new();
    for (i, center) in seed_centers.iter().enumerate() {
        let roi = spherical_roi::<f32>(&mask, center, 6.0, Some(1.0), true)?;
        println!("   Seed {}: {} voxels at {:?}", i + 1, roi.size(), center);
        seed_rois.push(roi);
    }

    // Example 5: ROI statistics
    println!("\n5. Computing ROI statistics...");
    for (i, roi) in seed_rois.iter().enumerate() {
        // Get values from brain volume at ROI coordinates
        let values: Vec<f32> = roi.coords.indices()
            .iter()
            .filter_map(|&idx| {
                let dense = brain.as_dense().ok()?;
                dense.data.as_slice().unwrap().get(idx).copied()
            })
            .collect();

        if !values.is_empty() {
            let mean = values.iter().sum::<f32>() / values.len() as f32;
            let std = {
                let variance = values.iter()
                    .map(|&v| (v - mean).powi(2))
                    .sum::<f32>() / values.len() as f32;
                variance.sqrt()
            };

            println!("   ROI {}: mean = {:.2}, std = {:.2}", i + 1, mean, std);
        }
    }

    println!("\nROI analysis complete!");

    Ok(())
}

