//! Neuroim - A Rust library for neuroimaging data structures and operations
//!
//! This crate provides efficient implementations of neuroimaging data structures
//! including 3D volumes, 4D time series, and supporting utilities for
//! spatial transformations, I/O, and analysis.
//!
//! # Quick Start
//!
//! ```no_run
//! use neuroim::{read_nifti, write_nifti, gaussian_blur, gaussian_kernel};
//! use neuroim::error::Result;
//!
//! fn main() -> Result<()> {
//!     // Read a NIfTI file
//!     let volume = read_nifti::<f32>("brain.nii.gz")?;
//!     
//!     // Apply Gaussian smoothing
//!     let kernel = gaussian_kernel(3.0)?; // 3mm FWHM
//!     let smoothed = gaussian_blur(&volume, &kernel)?;
//!     
//!     // Write the result
//!     write_nifti("brain_smoothed.nii.gz", &smoothed)?;
//!     
//!     Ok(())
//! }
//! ```
//!
//! # Core Concepts
//!
//! ## NeuroSpace
//! 
//! Defines the geometric properties of neuroimaging data:
//!
//! ```
//! use neuroim::NeuroSpace;
//!
//! let space = NeuroSpace::new(
//!     vec![91, 109, 91],           // dimensions
//!     Some(vec![2.0, 2.0, 2.0]),   // voxel spacing in mm
//!     None,                         // origin (defaults to center)
//!     None,                         // orientation (defaults to RAS)
//!     None,                         // coordinate transform
//! ).unwrap();
//! ```
//!
//! ## NeuroVol
//!
//! 3D volumes with various representations:
//!
//! ```
//! use neuroim::{DenseNeuroVol, SparseNeuroVol, LogicalNeuroVol};
//! use ndarray::Array3;
//! # use neuroim::NeuroSpace;
//! # let space = NeuroSpace::new(vec![10, 10, 10], None, None, None, None).unwrap();
//!
//! // Dense volume (full data)
//! let data = Array3::<f32>::zeros((10, 10, 10));
//! let dense = DenseNeuroVol::new(data, space.clone()).unwrap();
//!
//! // Sparse volume (efficient for mostly zeros)
//! let sparse = SparseNeuroVol::<f32>::zeros(space.clone()).unwrap();
//!
//! // Binary mask
//! let mask_data = Array3::<bool>::from_elem((10, 10, 10), false);
//! let mask = LogicalNeuroVol::new(mask_data, space).unwrap();
//! ```

#![warn(missing_docs)]
#![warn(clippy::all)]
#![warn(clippy::pedantic)]
#![allow(clippy::module_name_repetitions)]

pub mod axis;
pub mod error;
pub mod numeric;
pub mod neuro_space;
pub mod neuro_vol;
pub mod neuro_vec;
pub mod neuro_slice;
pub mod orthogonal_slices;
pub mod roi;
pub mod io;
pub mod kernel;
pub mod filter;
pub mod resample;
pub mod searchlight;
pub mod connected_components;
//pub mod stats;
//pub mod utils;

// Re-export commonly used items
pub use axis::{NamedAxis, AxisSet, AxisSet1D, AxisSet2D, AxisSet3D, AxisSet4D, AxisSet5D};
pub use error::{Error, Result};
pub use numeric::{Numeric, AsFloat};
pub use neuro_space::NeuroSpace;
pub use neuro_vol::{NeuroVol, DenseNeuroVol, LogicalNeuroVol, SparseNeuroVol, ClusteredNeuroVol};
pub use neuro_vec::{NeuroVecTrait, DenseNeuroVec, SparseNeuroVec};
pub use neuro_slice::NeuroSlice;
pub use orthogonal_slices::{SliceType, extract_orthogonal_slices};
pub use roi::{ROI, ROICoords, ROIVol, ROIVec, ROIVolWindow, spherical_roi, spherical_roi_coords, spherical_roi_coords_set, cuboid_roi, square_roi};
pub use kernel::{Kernel, gaussian_kernel, spherical_kernel, box_kernel, embed_kernel};
pub use filter::{gaussian_blur, guided_filter, bilateral_filter};
pub use resample::{resample, resample_vec, reorient, InterpolationMethod, OrientSpec};
pub use searchlight::{searchlight, searchlight_coords, random_searchlight, bootstrap_searchlight, clustered_searchlight, SearchlightResult};
