//! Connected components and spatial clustering analysis

use neuroim::{
    read_nifti, write_nifti, NeuroVol, LogicalNeuroVol, DenseNeuroVol,
    conn_comp, conn_comp_3d, ConnCompResult, ClusterTable,
    spherical_roi
};
use neuroim::error::Result;
use ndarray::Array3;
use std::collections::HashMap;

fn main() -> Result<()> {
    println!("=== Connected Components & Clustering Demo ===\n");

    // Read brain volume
    println!("1. Loading brain volume and creating masks...");
    let brain = read_nifti::<f32>("data/brain.nii.gz")?;

    // Create brain mask
    let threshold = 100.0;
    let mask_data = brain.as_dense()?.data.mapv(|v| v > threshold);
    let brain_mask = LogicalNeuroVol::new(mask_data, brain.space().clone())?;

    println!("   Brain mask contains {} voxels", 
             brain_mask.data.iter().filter(|&&v| v).count());

    // Example 1: Create synthetic activation map with multiple clusters
    println!("\n2. Creating synthetic activation map with multiple clusters...");

    let dims = brain.dim();
    let mut activation_data = Array3::<f32>::zeros((dims[0], dims[1], dims[2]));

    // Define cluster centers and their activation strengths
    let cluster_centers = vec![
        ((30, 40, 50), 8.0, 120.0),   // Left motor cortex
        ((60, 40, 50), 6.0, 110.0),   // Right motor cortex  
        ((45, 60, 45), 5.0, 100.0),   // Frontal cortex
        ((20, 70, 40), 4.0, 90.0),    // Left occipital
        ((70, 70, 40), 4.0, 95.0),    // Right occipital
        ((45, 30, 30), 3.0, 85.0),    // Temporal cortex
        ((35, 55, 60), 2.0, 80.0),    // Small parietal cluster
    ];

    // Create Gaussian-like clusters
    for &((cx, cy, cz), radius, intensity) in &cluster_centers {
        for x in 0..dims[0] {
            for y in 0..dims[1] {
                for z in 0..dims[2] {
                    let dx = x as f32 - cx as f32;
                    let dy = y as f32 - cy as f32;
                    let dz = z as f32 - cz as f32;
                    let distance = (dx*dx + dy*dy + dz*dz).sqrt();

                    if distance <= radius {
                        let gaussian = intensity * (-0.5 * (distance / (radius/3.0)).powi(2)).exp();
                        activation_data[[x, y, z]] = activation_data[[x, y, z]].max(gaussian);
                    }
                }
            }
        }
    }

    // Apply brain mask to activation
    for x in 0..dims[0] {
        for y in 0..dims[1] {
            for z in 0..dims[2] {
                if !brain_mask.data[[x, y, z]] {
                    activation_data[[x, y, z]] = 0.0;
                }
            }
        }
    }

    let activation_volume = DenseNeuroVol::new(activation_data, brain.space().clone())?;
    write_nifti("examples/data/synthetic_activation.nii.gz", &activation_volume)?;
    println!("   Created synthetic activation map with {} clusters", cluster_centers.len());

    // Example 2: Threshold and find connected components at different levels
    println!("\n3. Finding connected components at different thresholds...");

    let thresholds = vec![70.0, 80.0, 90.0, 100.0];
    let mut cluster_tables = Vec::new();

    for &thresh in &thresholds {
        println!("   Analyzing clusters at threshold {}...", thresh);

        // Create binary mask at threshold
        let thresholded_data = activation_volume.data.mapv(|v| v > thresh);
        let thresholded_mask = LogicalNeuroVol::new(thresholded_data, brain.space().clone())?;

        // Find connected components
        let conn_result = conn_comp(&thresholded_mask)?;

        // Create cluster table with sizes and peak intensities
        let mut cluster_table = ClusterTable::new();

        for cluster_id in 1..=conn_result.n_clusters {
            let mut cluster_voxels = Vec::new();
            let mut peak_intensity = 0.0;
            let mut peak_coords = (0, 0, 0);

            for x in 0..dims[0] {
                for y in 0..dims[1] {
                    for z in 0..dims[2] {
                        if conn_result.cluster_map.data[[x, y, z]] == cluster_id as i32 {
                            cluster_voxels.push((x, y, z));
                            let intensity = activation_volume.data[[x, y, z]];
                            if intensity > peak_intensity {
                                peak_intensity = intensity;
                                peak_coords = (x, y, z);
                            }
                        }
                    }
                }
            }

            cluster_table.add_cluster(
                cluster_id,
                cluster_voxels.len(),
                peak_coords,
                peak_intensity
            );
        }

        println!("     Found {} clusters", conn_result.n_clusters);

        // Save thresholded map and cluster map
        let thresh_filename = format!("examples/data/activation_thresh_{}.nii.gz", thresh as i32);
        write_nifti(&thresh_filename, &thresholded_mask)?;

        let cluster_filename = format!("examples/data/clusters_thresh_{}.nii.gz", thresh as i32);
        write_nifti(&cluster_filename, &conn_result.cluster_map)?;

        cluster_tables.push((thresh, cluster_table));
    }

    // Example 3: Detailed analysis of clusters at optimal threshold
    println!("\n4. Detailed cluster analysis at threshold 80...");
    let optimal_thresh = 80.0;

    let thresholded_data = activation_volume.data.mapv(|v| v > optimal_thresh);
    let thresholded_mask = LogicalNeuroVol::new(thresholded_data, brain.space().clone())?;
    let conn_result = conn_comp(&thresholded_mask)?;

    // Analyze each cluster in detail
    let mut cluster_stats = Vec::new();

    for cluster_id in 1..=conn_result.n_clusters {
        let mut voxel_coords = Vec::new();
        let mut intensities = Vec::new();

        for x in 0..dims[0] {
            for y in 0..dims[1] {
                for z in 0..dims[2] {
                    if conn_result.cluster_map.data[[x, y, z]] == cluster_id as i32 {
                        voxel_coords.push((x, y, z));
                        intensities.push(activation_volume.data[[x, y, z]]);
                    }
                }
            }
        }

        if !intensities.is_empty() {
            let size = intensities.len();
            let mean_intensity = intensities.iter().sum::<f32>() / size as f32;
            let max_intensity = intensities.iter().fold(f32::NEG_INFINITY, |a, &b| a.max(b));
            let std_intensity = {
                let variance = intensities.iter()
                    .map(|&x| (x - mean_intensity).powi(2))
                    .sum::<f32>() / size as f32;
                variance.sqrt()
            };

            // Find center of mass
            let com_x = voxel_coords.iter().map(|&(x, _, _)| x).sum::<usize>() as f32 / size as f32;
            let com_y = voxel_coords.iter().map(|&(_, y, _)| y).sum::<usize>() as f32 / size as f32;
            let com_z = voxel_coords.iter().map(|&(_, _, z)| z).sum::<usize>() as f32 / size as f32;

            cluster_stats.push((cluster_id, size, mean_intensity, max_intensity, std_intensity, (com_x, com_y, com_z)));

            println!("   Cluster {}: {} voxels, mean={:.1}, max={:.1}, std={:.1}, COM=({:.1},{:.1},{:.1})",
                     cluster_id, size, mean_intensity, max_intensity, std_intensity, com_x, com_y, com_z);
        }
    }

    // Example 4: Cluster size filtering and refinement
    println!("\n5. Filtering clusters by size (minimum 10 voxels)...");

    let min_cluster_size = 10;
    let mut filtered_cluster_data = Array3::<i32>::zeros((dims[0], dims[1], dims[2]));
    let mut filtered_cluster_id = 1;

    for (cluster_id, size, _, _, _, _) in &cluster_stats {
        if *size >= min_cluster_size {
            for x in 0..dims[0] {
                for y in 0..dims[1] {
                    for z in 0..dims[2] {
                        if conn_result.cluster_map.data[[x, y, z]] == *cluster_id as i32 {
                            filtered_cluster_data[[x, y, z]] = filtered_cluster_id;
                        }
                    }
                }
            }
            println!("   Retained cluster {} (original {}) with {} voxels", 
                     filtered_cluster_id, cluster_id, size);
            filtered_cluster_id += 1;
        } else {
            println!("   Removed cluster {} with {} voxels (too small)", cluster_id, size);
        }
    }

    let filtered_clusters = DenseNeuroVol::new(filtered_cluster_data, brain.space().clone())?;
    write_nifti("examples/data/clusters_filtered.nii.gz", &filtered_clusters)?;

    // Example 5: 3D connected components with different connectivity
    println!("\n6. Comparing 6-connected vs 26-connected clustering...");

    // Test different connectivity patterns
    let connectivities = vec![
        ("6-connected", false),   // Face connectivity only
        ("26-connected", true),   // Face, edge, and vertex connectivity
    ];

    for (name, use_26_conn) in connectivities {
        println!("   Running {} analysis...", name);

        let conn_result_3d = if use_26_conn {
            conn_comp_3d(&thresholded_mask, true)?
        } else {
            conn_comp_3d(&thresholded_mask, false)?
        };

        println!("     Found {} clusters with {} connectivity", 
                 conn_result_3d.n_clusters, name);

        let filename = format!("examples/data/clusters_{}.nii.gz", 
                              if use_26_conn { "26conn" } else { "6conn" });
        write_nifti(&filename, &conn_result_3d.cluster_map)?;
    }

    // Example 6: Hierarchical clustering analysis
    println!("\n7. Hierarchical threshold analysis...");

    let mut hierarchy_data = Vec::new();
    let fine_thresholds = (70..=110).step_by(5).map(|t| t as f32).collect::<Vec<_>>();

    for &thresh in &fine_thresholds {
        let thresh_data = activation_volume.data.mapv(|v| v > thresh);
        let thresh_mask = LogicalNeuroVol::new(thresh_data, brain.space().clone())?;
        let conn_result = conn_comp(&thresh_mask)?;

        let total_voxels = thresh_mask.data.iter().filter(|&&v| v).count();
        hierarchy_data.push((thresh, conn_result.n_clusters, total_voxels));

        println!("   Threshold {}: {} clusters, {} total voxels", 
                 thresh, conn_result.n_clusters, total_voxels);
    }

    // Save comprehensive analysis report
    println!("\n8. Generating analysis report...");

    let mut report = String::from("Connected Components Analysis Report\n");
    report.push_str("=====================================\n\n");

    report.push_str("Threshold Analysis:\n");
    report.push_str("-------------------\n");
    for (thresh, n_clusters, total_voxels) in &hierarchy_data {
        report.push_str(&format!("Threshold {}: {} clusters, {} voxels\n", 
                                thresh, n_clusters, total_voxels));
    }

    report.push_str("\nDetailed Cluster Analysis (threshold 80):\n");
    report.push_str("------------------------------------------\n");
    for (cluster_id, size, mean_int, max_int, std_int, (com_x, com_y, com_z)) in &cluster_stats {
        if *size >= min_cluster_size {
            report.push_str(&format!(
                "Cluster {}: {} voxels\n  Intensity: mean={:.1}, max={:.1}, std={:.1}\n  Center of mass: ({:.1}, {:.1}, {:.1})\n\n",
                cluster_id, size, mean_int, max_int, std_int, com_x, com_y, com_z
            ));
        }
