    report.push_str("\nFiles Generated:\n");
    report.push_str("----------------\n");
    report.push_str("- synthetic_activation.nii.gz: Original activation map\n");
    report.push_str("- activation_thresh_*.nii.gz: Thresholded binary maps\n");
    report.push_str("- clusters_thresh_*.nii.gz: Cluster label maps\n");
    report.push_str("- clusters_filtered.nii.gz: Size-filtered clusters\n");
    report.push_str("- clusters_6conn.nii.gz: 6-connected clustering\n");
    report.push_str("- clusters_26conn.nii.gz: 26-connected clustering\n");

    std::fs::write("examples/data/clustering_report.txt", report)?;
    println!("   Analysis report saved to examples/data/clustering_report.txt");

    println!("\n=== Connected Components Analysis Complete! ===");

    Ok(())
}

