//! Geometric specification of image space
//!
//! This module provides the `NeuroSpace` struct which maps grid coordinates
//! to real-world coordinates using affine transformations.

use nalgebra::{DMatrix, DVector};
use ndarray::{Array1, Array2};
use serde::{Deserialize, Serialize};
use std::fmt;

use crate::axis::{AxisSet, AxisSet3D, AnyAxisSet, find_anatomy_3d, axis_set};
use crate::error::{Error, Result};

/// Geometric specification of image space
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct NeuroSpace {
    /// Dimensions of the image space
    pub dim: Vec<usize>,
    /// Voxel dimensions
    pub spacing: Vec<f64>,
    /// Origin coordinates
    pub origin: Vec<f64>,
    /// Axis specification
    pub axes: AnyAxisSet,
    /// Transformation matrix (4x4 for 3D or smaller, larger for 4D+)
    pub trans: DMatrix<f64>,
    /// Inverse transformation matrix
    pub inverse: Option<DMatrix<f64>>,
}

impl NeuroSpace {
    /// Create a new NeuroSpace
    pub fn new(
        dim: Vec<usize>,
        spacing: Option<Vec<f64>>,
        origin: Option<Vec<f64>>,
        axes: Option<AnyAxisSet>,
        trans: Option<DMatrix<f64>>,
    ) -> Result<Self> {
        // Validate dimensions
        if dim.is_empty() {
            return Err(Error::InvalidDimensions("Dimensions cannot be empty".to_string()));
        }
        if dim.iter().any(|&d| d == 0) {
            return Err(Error::InvalidDimensions("All dimensions must be positive".to_string()));
        }

        let ndim = dim.len();

        // Set defaults if not provided
        let spacing = spacing.unwrap_or_else(|| vec![1.0; ndim]);
        let origin = origin.unwrap_or_else(|| vec![0.0; ndim]);

        // Validate spacing
        if spacing.len() != ndim {
            return Err(Error::InvalidDimensions(
                format!("Spacing length ({}) must match dimension count ({})", spacing.len(), ndim)
            ));
        }
        if spacing.iter().any(|&s| s <= 0.0) {
            return Err(Error::InvalidDimensions("Spacing values must be positive".to_string()));
        }

        if origin.len() != ndim {
            return Err(Error::InvalidDimensions(
                format!("Origin length ({}) must match dimension count ({})", origin.len(), ndim)
            ));
        }

        // Handle transformation matrix
        let (trans, extracted_spacing, extracted_origin) = if let Some(t) = trans {
            // Validate transformation matrix size
            let expected_size = if ndim <= 3 { 4 } else { ndim + 1 };
            if ndim <= 3 && (t.nrows() != 4 || t.ncols() != 4) {
                return Err(Error::InvalidTransformation(
                    format!("Transformation matrix must be 4x4 for {}D space, got {}x{}", 
                            ndim, t.nrows(), t.ncols())
                ));
            } else if ndim > 3 {
                if t.nrows() == 4 && t.ncols() == 4 {
                    // Extend 4x4 matrix for higher dimensions
                    let mut full_trans = DMatrix::identity(ndim + 1, ndim + 1);
                    full_trans.view_mut((0, 0), (3, 3)).copy_from(&t.view((0, 0), (3, 3)));
                    full_trans.view_mut((0, ndim), (3, 1)).copy_from(&t.view((0, 3), (3, 1)));
                    // Additional dimensions get identity scaling
                    for i in 3..ndim {
                        full_trans[(i, i)] = spacing.get(i).copied().unwrap_or(1.0);
                    }
                    (full_trans, spacing, origin)
                } else if t.nrows() != expected_size || t.ncols() != expected_size {
                    return Err(Error::InvalidTransformation(
                        format!("Transformation matrix must be {}x{} for {}D space, got {}x{}",
                                expected_size, expected_size, ndim, t.nrows(), t.ncols())
                    ));
                } else {
                    (t, spacing, origin)
                }
            } else {
                (t, spacing, origin)
            }

