//! Resampling and interpolation operations for neuroimaging data
//!
//! This module provides functionality to transform neuroimaging data between
//! different spatial resolutions and coordinate systems.

use ndarray::{Array3, Array4};
use nalgebra::{Matrix4, Vector4};

use crate::error::{Error, Result};
use crate::neuro_space::NeuroSpace;
use crate::neuro_vol::{NeuroVol, DenseNeuroVol};
use crate::neuro_vec::{NeuroVecTrait, DenseNeuroVec};
use crate::numeric::Numeric;
use crate::AsFloat;
use crate::axis::{AxisSet3D, match_axis, AnyAxisSet};

/// Interpolation method for resampling
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum InterpolationMethod {
    /// Nearest neighbor interpolation (order 0)
    NearestNeighbor,
    /// Linear interpolation (order 1)
    Linear,
    /// Cubic interpolation (order 3)
    Cubic,
}

impl InterpolationMethod {
    /// Create from integer code (matching scipy.ndimage conventions)
    pub fn from_code(code: i32) -> Result<Self> {
        match code {
            0 => Ok(InterpolationMethod::NearestNeighbor),
            1 => Ok(InterpolationMethod::Linear),
            3 => Ok(InterpolationMethod::Cubic),
            _ => Err(Error::InvalidParameter(
                format!("Invalid interpolation code: {}. Must be 0 (nearest), 1 (linear), or 3 (cubic)", code)
            )),
        }
    }
}

/// Resample a volume to a new space
///
/// # Arguments
/// * `source` - Source volume to resample
/// * `target` - Target space or volume to resample to
/// * `interpolation` - Interpolation method (0=nearest, 1=linear, 3=cubic)
pub fn resample<T: Numeric + AsFloat, Target>(
    source: &DenseNeuroVol<T>,
    target: Target,
    interpolation: Option<i32>,
) -> Result<DenseNeuroVol<T>>
where
    Target: AsTargetSpace,
{
    let target_space = target.as_target_space();
    let method = InterpolationMethod::from_code(interpolation.unwrap_or(1))?;

    // Create output array
    let target_shape = (target_space.dim[0], target_space.dim[1], target_space.dim[2]);

