//! NeuroSpace and resampling operations demo

use neuroim::{
    read_nifti, write_nifti, NeuroSpace, NeuroVol, DenseNeuroVol,
    resample, resample_vec, reorient, InterpolationMethod, OrientSpec
};
use neuroim::error::Result;
use ndarray::Array3;

fn main() -> Result<()> {
    println!("=== NeuroSpace & Resampling Demo ===\n");

    // Example 1: Creating custom NeuroSpace
    println!("1. Creating custom NeuroSpace configurations...");

    // High-resolution space (1mm isotropic)
    let high_res_space = NeuroSpace::new(
        vec![181, 217, 181],           // MNI152 1mm dimensions
        Some(vec![1.0, 1.0, 1.0]),     // 1mm isotropic voxels
        None,                          // Default origin
        None,                          // Default RAS orientation
        None,                          // No additional transform
    )?;

    // Low-resolution space (4mm isotropic) 
    let low_res_space = NeuroSpace::new(
        vec![45, 54, 45],              // Downsampled dimensions
        Some(vec![4.0, 4.0, 4.0]),     // 4mm isotropic voxels
        None,
        None,
        None,
    )?;

    // Anisotropic space (different spacing per axis)
    let aniso_space = NeuroSpace::new(
        vec![64, 64, 30],              // Typical EPI dimensions
        Some(vec![3.0, 3.0, 4.0]),     // 3x3x4mm voxels (EPI-like)
        None,
        None,
        None,
    )?;

    println!("   High-res space: {:?} with spacing {:?}", 
             high_res_space.dim, high_res_space.spacing);
    println!("   Low-res space: {:?} with spacing {:?}", 
             low_res_space.dim, low_res_space.spacing);
    println!("   Anisotropic space: {:?} with spacing {:?}", 
             aniso_space.dim, aniso_space.spacing);

    // Example 2: Create synthetic volumes in different spaces
    println!("\n2. Creating synthetic volumes in different spaces...");

    // Create a synthetic volume with spatial gradients
    let create_gradient_volume = |space: &NeuroSpace| -> Result<DenseNeuroVol<f32>> {
        let dims = &space.dim;
        let mut data = Array3::<f32>::zeros((dims[0], dims[1], dims[2]));

        for x in 0..dims[0] {
            for y in 0..dims[1] {
                for z in 0..dims[2] {
                    // Create a 3D gradient pattern
                    let value = (x as f32 / dims[0] as f32) * 100.0 +
                               (y as f32 / dims[1] as f32) * 50.0 +
                               (z as f32 / dims[2] as f32) * 25.0;
                    data[[x, y, z]] = value;
                }
            }
        }

        DenseNeuroVol::new(data, space.clone())
    };

    let high_res_vol = create_gradient_volume(&high_res_space)?;
    let low_res_vol = create_gradient_volume(&low_res_space)?;
    let aniso_vol = create_gradient_volume(&aniso_space)?;

    // Save original volumes
    write_nifti("examples/data/gradient_highres.nii.gz", &high_res_vol)?;
    write_nifti("examples/data/gradient_lowres.nii.gz", &low_res_vol)?;
    write_nifti("examples/data/gradient_aniso.nii.gz", &aniso_vol)?;

    println!("   Created gradient volumes in different spaces");

    // Example 3: Resampling between spaces with different interpolation methods
    println!("\n3. Resampling between different spaces...");

    let interpolation_methods = vec![
        ("nearest", InterpolationMethod::Nearest),
        ("linear", InterpolationMethod::Linear),
        ("cubic", InterpolationMethod::Cubic),
    ];

    for (name, method) in interpolation_methods {
        println!("   Resampling high-res to low-res using {} interpolation...", name);

        // Resample high-res volume to low-res space
        let resampled = resample(&high_res_vol, &low_res_space, method)?;
        let filename = format!("examples/data/resampled_highres_to_lowres_{}.nii.gz", name);
        write_nifti(&filename, &resampled)?;

        // Resample back to high-res to see information loss
        let resampled_back = resample(&resampled, &high_res_space, method)?;
        let filename_back = format!("examples/data/resampled_roundtrip_{}.nii.gz", name);
        write_nifti(&filename_back, &resampled_back)?;

        println!("     Saved {} and {}", filename, filename_back);
    }

    // Example 4: Anisotropic to isotropic resampling
    println!("\n4. Converting anisotropic to isotropic spacing...");

    // Target isotropic space (3mm isotropic)
    let target_iso_space = NeuroSpace::new(
        vec![64, 64, 40],              // Adjusted dimensions for 3mm iso
        Some(vec![3.0, 3.0, 3.0]),     // 3mm isotropic
        None,
        None,
        None,
    )?;

    let iso_resampled = resample(&aniso_vol, &target_iso_space, InterpolationMethod::Linear)?;
    write_nifti("examples/data/aniso_to_isotropic.nii.gz", &iso_resampled)?;

    println!("   Resampled anisotropic ({:?}) to isotropic ({:?})",
             aniso_space.spacing, target_iso_space.spacing);

    // Example 5: Volume reorientation
    println!("\n5. Demonstrating volume reorientation...");

    // Try different orientation specifications
    let orientations = vec![
        ("RAS", OrientSpec::RAS),  // Radiological (default)
        ("LAS", OrientSpec::LAS),  // Neurological
        ("LPS", OrientSpec::LPS),  // DICOM standard
    ];

    for (name, orient_spec) in orientations {
        println!("   Reorienting to {} orientation...", name);

        let reoriented = reorient(&high_res_vol, orient_spec)?;
        let filename = format!("examples/data/reoriented_{}.nii.gz", name.to_lowercase());
        write_nifti(&filename, &reoriented)?;

        println!("     Saved to {}", filename);
        println!("     New dimensions: {:?}", reoriented.space().dim);
    }

    // Example 6: Vector field resampling
    println!("\n6. Vector field resampling demo...");

    // Create a synthetic 3D vector field (e.g., displacement field)
    let vector_dims = &low_res_space.dim;
    let mut vector_data = Vec::new();

    for component in 0..3 {
        let mut comp_data = Array3::<f32>::zeros((vector_dims[0], vector_dims[1], vector_dims[2]));

        for x in 0..vector_dims[0] {
            for y in 0..vector_dims[1] {
                for z in 0..vector_dims[2] {
                    // Create a swirling pattern for each component
                    let cx = vector_dims[0] as f32 / 2.0;
                    let cy = vector_dims[1] as f32 / 2.0;
                    let cz = vector_dims[2] as f32 / 2.0;

                    let dx = x as f32 - cx;
                    let dy = y as f32 - cy;
                    let dz = z as f32 - cz;

                    let value = match component {
                        0 => -dy * 0.1,      // x-component
                        1 => dx * 0.1,       // y-component  
                        2 => dz * 0.05,      // z-component
                        _ => 0.0,
                    };

                    comp_data[[x, y, z]] = value;
                }
            }
        }

        vector_data.push(DenseNeuroVol::new(comp_data, low_res_space.clone())?);
    }

    // Resample vector field to high resolution
    println!("   Resampling 3-component vector field...");
    let resampled_vectors = resample_vec(&vector_data, &high_res_space, InterpolationMethod::Linear)?;

    for (i, component) in resampled_vectors.iter().enumerate() {
        let filename = format!("examples/data/vector_field_component_{}.nii.gz", i);
        write_nifti(&filename, component)?;
    }

    println!("   Saved vector field components to examples/data/vector_field_component_*.nii.gz");

    // Example 7: Compute resampling quality metrics
    println!("\n7. Computing resampling quality metrics...");

    // Compare original vs resampled data
    let original_mean = {
        let data = high_res_vol.as_dense()?.data.as_slice().unwrap();
        data.iter().sum::<f32>() / data.len() as f32
    };

    let resampled_linear = resample(&high_res_vol, &low_res_space, InterpolationMethod::Linear)?;
    let upsampled_back = resample(&resampled_linear, &high_res_space, InterpolationMethod::Linear)?;

    let upsampled_mean = {
        let data = upsampled_back.as_dense()?.data.as_slice().unwrap();
        data.iter().sum::<f32>() / data.len() as f32
    };

    // Calculate mean squared error
    let mse = {
        let orig_data = high_res_vol.as_dense()?.data.as_slice().unwrap();
        let ups_data = upsampled_back.as_dense()?.data.as_slice().unwrap();

        orig_data.iter().zip(ups_data.iter())
            .map(|(&o, &u)| (o - u).powi(2))
            .sum::<f32>() / orig_data.len() as f32
    };

    println!("   Original volume mean: {:.2}", original_mean);
    println!("   Roundtrip resampled mean: {:.2}", upsampled_mean);
    println!("   Mean squared error: {:.4}", mse);
    println!("   Relative error: {:.2}%", ((upsampled_mean - original_mean) / original_mean * 100.0).abs());

    // Save analysis summary
    let summary = format!(
        "NeuroSpace & Resampling Analysis Summary\n\
         =======================================\n\
         \n\
         Spaces created:\n\
         - High resolution: {:?} @ {:?}mm\n\
         - Low resolution: {:?} @ {:?}mm\n\
         - Anisotropic: {:?} @ {:?}mm\n\
         \n\
         Resampling quality (linear interpolation):\n\
         - Original mean: {:.2}\n\
         - Roundtrip mean: {:.2}\n\
         - MSE: {:.4}\n\
         - Relative error: {:.2}%\n\
         \n\
         Files generated:\n\
         - Gradient volumes in different spaces\n\
         - Resampled volumes with different interpolation methods\n\
         - Reoriented volumes (RAS, LAS, LPS)\n\
         - Vector field components\n",
        high_res_space.dim, high_res_space.spacing,
        low_res_space.dim, low_res_space.spacing,
        aniso_space.dim, aniso_space.spacing,
        original_mean, upsampled_mean, mse,
        ((upsampled_mean - original_mean) / original_mean * 100.0).abs()
    );

    std::fs::write("examples/data/resampling_summary.txt", summary)?;
    println!("\n   Summary saved to examples/data/resampling_summary.txt");

    println!("\n=== NeuroSpace & Resampling Demo Complete! ===");

    Ok(())
}

