         \n\
         Files generated:\n\
         - Gradient volumes in different spaces\n\
         - Resampled volumes with different interpolation methods\n\
         - Reoriented volumes (RAS, LAS, LPS)\n\
         - Vector field components\n",
        high_res_space.dim, high_res_space.spacing,
        low_res_space.dim, low_res_space.spacing,
        aniso_space.dim, aniso_space.spacing,
        original_mean, upsampled_mean, mse,
        ((upsampled_mean - original_mean) / original_mean * 100.0).abs()
    );

    std::fs::write("examples/data/resampling_summary.txt", summary)?;
    println!("\n   Summary saved to examples/data/resampling_summary.txt");

    println!("\n=== NeuroSpace & Resampling Demo Complete! ===");

    Ok(())
}

