//! Searchlight functionality for neuroimaging analysis
//!
//! This module provides searchlight iterators for analyzing local neighborhoods
//! of voxels within brain masks. Includes exhaustive, random, and clustered
//! searchlight implementations.

use rand::prelude::*;
use std::collections::HashSet;

use crate::error::{Error, Result};
use crate::neuro_vol::{NeuroVol, LogicalNeuroVol};
use crate::roi::{ROIVolWindow, ROIVol, spherical_roi};
use crate::numeric::{Numeric, AsFloat};

/// LazyList implementation for deferred computation
pub struct LazyList<T> {
    generator: Box<dyn Fn(usize) -> T>,
    length: usize,
}

impl<T> LazyList<T> {
    /// Create a new LazyList
    pub fn new<F>(generator: F, length: usize) -> Self
    where
        F: Fn(usize) -> T + 'static,
    {
        Self {
            generator: Box::new(generator),
            length,
        }
    }

    /// Get the length of the list
    pub fn len(&self) -> usize {
        self.length
    }

    /// Check if empty
    pub fn is_empty(&self) -> bool {
        self.length == 0
    }

    /// Get an item at index
    pub fn get(&self, index: usize) -> Option<T> {
        if index < self.length {
            Some((self.generator)(index))
        } else {
            None
        }
    }

