//! Searchlight analysis for multivariate pattern analysis (MVPA)

use neuroim::{
    read_nifti, write_nifti, NeuroVol, LogicalNeuroVol,
    searchlight, random_searchlight, bootstrap_searchlight,
    spherical_roi, SearchlightResult
};
use neuroim::error::Result;
use ndarray::Array1;
use std::collections::HashMap;

fn main() -> Result<()> {
    println!("=== Searchlight Analysis Demo ===\n");

    // Read brain volume for analysis
    println!("1. Loading brain volume...");
    let brain = read_nifti::<f32>("data/brain.nii.gz")?;

    // Create a brain mask
    println!("2. Creating brain mask...");
    let threshold = 100.0;
    let mask_data = brain.as_dense()?.data.mapv(|v| v > threshold);
    let mask = LogicalNeuroVol::new(mask_data, brain.space().clone())?;

    println!("   Brain mask contains {} voxels", mask.data.iter().filter(|&&v| v).count());

    // Simulate multi-condition data (e.g., different experimental conditions)
    println!("\n3. Simulating multi-condition fMRI data...");
    let n_conditions = 4;
    let n_timepoints = 100;

    // Create synthetic data with different activation patterns
    let mut condition_data = Vec::new();
    for condition in 0..n_conditions {
        println!("   Generating condition {} data...", condition + 1);

        // Create condition-specific activation pattern
        let mut data = brain.as_dense()?.clone();

        // Add simulated activation in different brain regions for each condition
        let activation_centers = match condition {
            0 => vec![(30, 40, 50), (60, 40, 50)], // Motor cortex bilateral
            1 => vec![(45, 60, 45)],               // Frontal cortex
            2 => vec![(20, 70, 40), (70, 70, 40)], // Occipital bilateral
            3 => vec![(45, 30, 30)],               // Temporal cortex
            _ => vec![],
        };

        for &(x, y, z) in &activation_centers {
            // Add activation in spherical region
            for dx in -5i32..=5 {
                for dy in -5i32..=5 {
                    for dz in -5i32..=5 {
                        let nx = (x as i32 + dx) as usize;
                        let ny = (y as i32 + dy) as usize;
                        let nz = (z as i32 + dz) as usize;

                        if dx*dx + dy*dy + dz*dz <= 25 { // Within radius
                            if let Ok(()) = data.set_at(nx, ny, nz, 
                                data.get_at(nx, ny, nz).unwrap_or(0.0) + 50.0 + condition as f32 * 10.0) {
                            }
                        }
                    }
                }
            }
        }

        condition_data.push(data);
    }

    // Example 1: Standard searchlight with classification
    println!("\n4. Running standard searchlight analysis...");
    let radius = 6.0; // 6mm radius searchlights

    // Simple mock classifier function (in practice, use real ML)
    let classifier = |data: &[Array1<f32>]| -> f64 {
        // Mock classification accuracy based on data variance
        let all_values: Vec<f32> = data.iter().flat_map(|arr| arr.iter()).copied().collect();
        if all_values.is_empty() { return 0.5; }

        let mean = all_values.iter().sum::<f32>() / all_values.len() as f32;
        let variance = all_values.iter()
            .map(|&x| (x - mean).powi(2))
            .sum::<f32>() / all_values.len() as f32;

        // Higher variance = better classification (mock)
        0.5 + (variance / 1000.0).min(0.5)
    };

    // Prepare data for searchlight
    let searchlight_data: Vec<Array1<f32>> = condition_data.iter()
        .map(|vol| {
            let dense = vol.as_dense().unwrap();
            Array1::from_vec(dense.data.as_slice().unwrap().to_vec())
        })
        .collect();

    let searchlight_result = searchlight(&mask, radius, &searchlight_data, classifier)?;

    // Save searchlight accuracy map
    write_nifti("examples/data/searchlight_accuracy.nii.gz", &searchlight_result.accuracy_map)?;
    println!("   Saved accuracy map to examples/data/searchlight_accuracy.nii.gz");

    // Print summary statistics
    let acc_values: Vec<f64> = searchlight_result.accuracy_map.data.iter()
        .filter(|&&v| v > 0.0)
        .copied()
        .collect();

    if !acc_values.is_empty() {
        let mean_acc = acc_values.iter().sum::<f64>() / acc_values.len() as f64;
        let max_acc = acc_values.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));
        println!("   Mean accuracy: {:.3}", mean_acc);
        println!("   Max accuracy: {:.3}", max_acc);
        println!("   Number of searchlights: {}", acc_values.len());
    }

    // Example 2: Random searchlight (for null distribution)
    println!("\n5. Running random searchlight for null distribution...");
    let n_random = 50; // Number of random searchlights
    let random_results = random_searchlight(&mask, radius, n_random, &searchlight_data, classifier)?;

    println!("   Random searchlight accuracies:");
    for (i, &acc) in random_results.iter().take(10).enumerate() {
        println!("     Random {}: {:.3}", i + 1, acc);
    }

    let mean_random = random_results.iter().sum::<f64>() / random_results.len() as f64;
    println!("   Mean random accuracy: {:.3}", mean_random);

    // Example 3: Statistical significance testing
    println!("\n6. Testing statistical significance...");

    // Find peak searchlight location
    let (peak_x, peak_y, peak_z, peak_acc) = {
        let acc_data = &searchlight_result.accuracy_map.data;
        let mut max_acc = 0.0;
        let mut peak_coords = (0, 0, 0);

        for x in 0..acc_data.dim().0 {
            for y in 0..acc_data.dim().1 {
                for z in 0..acc_data.dim().2 {
                    if acc_data[[x, y, z]] > max_acc {
                        max_acc = acc_data[[x, y, z]];
                        peak_coords = (x, y, z);
                    }
                }
            }
        }
        (peak_coords.0, peak_coords.1, peak_coords.2, max_acc)
    };

    println!("   Peak searchlight at coordinates: ({}, {}, {}) with accuracy: {:.3}", 
             peak_x, peak_y, peak_z, peak_acc);

    // Compare with random baseline
    let p_value_estimate = random_results.iter()
        .filter(|&&acc| acc >= peak_acc)
        .count() as f64 / random_results.len() as f64;

    println!("   Estimated p-value (compared to random): {:.3}", p_value_estimate);

    let is_significant = p_value_estimate < 0.05;
    println!("   Significant at p < 0.05: {}", is_significant);

    // Save results summary
    println!("\n7. Saving analysis summary...");
    let summary = format!(
        "Searchlight Analysis Summary\n\
         ============================\n\
         Radius: {:.1}mm\n\
         Total searchlights: {}\n\
         Mean accuracy: {:.3}\n\
         Max accuracy: {:.3}\n\
         Peak location: ({}, {}, {})\n\
         Random baseline: {:.3}\n\
         P-value estimate: {:.3}\n\
         Significant (p < 0.05): {}\n",
        radius,
        acc_values.len(),
        acc_values.iter().sum::<f64>() / acc_values.len() as f64,
        peak_acc,
        peak_x, peak_y, peak_z,
        mean_random,
        p_value_estimate,
        is_significant
    );

    std::fs::write("examples/data/searchlight_summary.txt", summary)?;
    println!("   Summary saved to examples/data/searchlight_summary.txt");

    println!("\n=== Searchlight Analysis Complete! ===");

    Ok(())
}

