use crate::neuro_vol::{NeuroVol, LogicalNeuroVol, DenseNeuroVol, ClusteredNeuroVol};
use crate::neuro_space::NeuroSpace;
use crate::numeric::{Numeric, AsFloat};

/// Result of connected components analysis
#[derive(Debug, Clone)]
pub struct ConnCompResult<T: Numeric> {
    /// Volume with cluster labels
    pub index: ClusteredNeuroVol,
    /// Volume with cluster sizes at each voxel
    pub size: DenseNeuroVol<T>,
    /// List of voxel coordinates for each cluster
    pub voxels: Vec<Array2<i32>>,
    /// Table with cluster statistics
    pub cluster_table: Option<ClusterTable>,
    /// Matrix of local maxima coordinates
    pub local_maxima: Option<Array2<f64>>,
}

/// Cluster statistics table
#[derive(Debug, Clone)]
pub struct ClusterTable {
    /// Cluster indices
    pub index: Vec<i32>,
    /// X coordinates of cluster centers
    pub x: Vec<f64>,
    /// Y coordinates of cluster centers
    pub y: Vec<f64>,
    /// Z coordinates of cluster centers
    pub z: Vec<f64>,
    /// Number of voxels in each cluster
    pub n: Vec<usize>,
    /// Volume in mm³ for each cluster
    pub area: Vec<f64>,
    /// Mean value in each cluster
    pub value: Vec<f64>,
}

impl ClusterTable {
    /// Get number of clusters
    pub fn len(&self) -> usize {
        self.index.len()
