    // Simple mock classifier function 
    let classifier = |data_vectors: &[Vec<f32>]| -> f64 {
        // Mock classification accuracy based on data variance
        let all_values: Vec<f32> = data_vectors.iter().flat_map(|v| v.iter()).copied().collect();
        if all_values.is_empty() { return 0.5; }

        let mean = all_values.iter().sum::<f32>() / all_values.len() as f32;
        let variance = all_values.iter()
            .map(|&x| (x - mean).powi(2))
            .sum::<f32>() / all_values.len() as f32;

        // Higher variance = better classification (mock)
        0.5 + (variance / 1000.0).min(0.5)
    };

    // Initialize accuracy map
    let dims = brain.space().dim.clone();
    let mut accuracy_map = Array3::<f32>::zeros((dims[0], dims[1], dims[2]));

    // Sample searchlight locations (every 4th voxel to speed up demo)
    let mut searchlight_count = 0;
    for x in (5..dims[0]-5).step_by(4) {
        for y in (5..dims[1]-5).step_by(4) {
            for z in (5..dims[2]-5).step_by(4) {
                // Check if center is in mask
                if !mask.data[[x, y, z]] {
                    continue;
                }

                // Create spherical ROI
                let center = [x as i32, y as i32, z as i32];
                if let Ok(roi) = spherical_roi::<f32>(&mask, &center, radius, Some(1.0), true) {
                    if roi.size() < 10 { // Skip very small searchlights
                        continue;
                    }

                    // Extract data for each condition from this ROI
                    let mut condition_vectors = Vec::new();
                    for cond_data in &condition_data {
                        let mut values = Vec::new();
                        for idx in roi.coords.indices() {
                            if let Some(val) = cond_data.as_dense().ok()
                                .and_then(|dense| dense.data.as_slice().unwrap().get(idx)) {
                                values.push(*val);
                            }
                        }
                        condition_vectors.push(values);
                    }

                    // Run classifier
                    let accuracy = classifier(&condition_vectors);
                    accuracy_map[[x, y, z]] = accuracy as f32;

                    searchlight_count += 1;
                }
            }
        }
    }

    println!("   Completed {} searchlights", searchlight_count);

    // Save searchlight accuracy map
    let accuracy_volume = DenseNeuroVol::new(accuracy_map.clone(), brain.space().clone())?;
    write_nifti("examples/data/searchlight_accuracy.nii.gz", &accuracy_volume)?;
    println!("   Saved accuracy map to examples/data/searchlight_accuracy.nii.gz");

    // Print summary statistics
    let acc_values: Vec<f32> = accuracy_map.iter()
        .filter(|&&v| v > 0.0)
        .copied()
        .collect();

    if !acc_values.is_empty() {
        let mean_acc = acc_values.iter().sum::<f32>() / acc_values.len() as f32;
        let max_acc = acc_values.iter().fold(f32::NEG_INFINITY, |a, &b| a.max(b));
        println!("   Mean accuracy: {:.3}", mean_acc);
        println!("   Max accuracy: {:.3}", max_acc);
        println!("   Number of searchlights: {}", acc_values.len());
    }

    // Example 2: Random baseline generation
    println!("\n5. Generating random baseline...");
    let n_random = 50;
    let mut random_accuracies = Vec::new();

    for i in 0..n_random {
        // Create random data vectors
        let mut random_vectors = Vec::new();
        for _ in 0..n_conditions {
            let values: Vec<f32> = (0..100).map(|_| rand::random::<f32>() * 200.0).collect();
            random_vectors.push(values);
        }

        let acc = classifier(&random_vectors);
        random_accuracies.push(acc);

        if i < 10 {
            println!("   Random {}: {:.3}", i + 1, acc);
        }
    }

    let mean_random = random_accuracies.iter().sum::<f64>() / random_accuracies.len() as f64;
    println!("   Mean random accuracy: {:.3}", mean_random);

    // Example 3: Statistical significance testing
    println!("\n6. Testing statistical significance...");

    // Find peak searchlight location
    let (peak_x, peak_y, peak_z, peak_acc) = {
        let mut max_acc = 0.0f32;
        let mut peak_coords = (0, 0, 0);

        for x in 0..dims[0] {
            for y in 0..dims[1] {
                for z in 0..dims[2] {
                    if accuracy_map[[x, y, z]] > max_acc {
                        max_acc = accuracy_map[[x, y, z]];
                        peak_coords = (x, y, z);
                    }
                }
            }
        }
        (peak_coords.0, peak_coords.1, peak_coords.2, max_acc as f64)
    };

    println!("   Peak searchlight at coordinates: ({}, {}, {}) with accuracy: {:.3}", 
             peak_x, peak_y, peak_z, peak_acc);

    // Compare with random baseline
    let p_value_estimate = random_accuracies.iter()
        .filter(|&&acc| acc >= peak_acc)
        .count() as f64 / random_accuracies.len() as f64;

    println!("   Estimated p-value (compared to random): {:.3}", p_value_estimate);

    let is_significant = p_value_estimate < 0.05;
    println!("   Significant at p < 0.05: {}", is_significant);

    // Save results summary
    println!("\n7. Saving analysis summary...");
    let summary = format!(
        "Searchlight Analysis Summary\n\
         ============================\n\
         Radius: {:.1}mm\n\
         Total searchlights: {}\n\
         Mean accuracy: {:.3}\n\
         Max accuracy: {:.3}\n\
         Peak location: ({}, {}, {})\n\
         Random baseline: {:.3}\n\
         P-value estimate: {:.3}\n\
         Significant (p < 0.05): {}\n",
        radius,
        acc_values.len(),
        acc_values.iter().sum::<f32>() / acc_values.len() as f32,
        peak_acc,
        peak_x, peak_y, peak_z,
        mean_random,
        p_value_estimate,
        is_significant
    );

    std::fs::write("examples/data/searchlight_summary.txt", summary)?;
    println!("   Summary saved to examples/data/searchlight_summary.txt");

    println!("\n=== Searchlight Analysis Complete! ===");

    Ok(())
}

