//! Spatial filtering operations for neuroimaging data
//!
//! This module provides various spatial filters for smoothing and processing
//! neuroimaging data, including Gaussian blur, guided filter, and bilateral filter.
//!
//! # Examples
//!
//! ## Gaussian Blur
//!
//! ```
//! use neuroim::{DenseNeuroVol, gaussian_blur, gaussian_kernel};
//! use ndarray::Array3;
//! # use neuroim::NeuroSpace;
//! # use neuroim::error::Result;
//! # fn main() -> Result<()> {
//! # let space = NeuroSpace::new(vec![10, 10, 10], None, None, None, None)?;
//! # let data = Array3::from_elem((10, 10, 10), 1.0f32);
//! # let volume = DenseNeuroVol::new(data, space)?;
//!
//! // Create a Gaussian kernel with 3mm FWHM
//! let kernel = gaussian_kernel(3.0)?;
//!
//! // Apply Gaussian smoothing
//! let smoothed = gaussian_blur(&volume, &kernel)?;
//! # Ok(())
//! # }
//! ```
//!
//! ## Bilateral Filter
//!
//! ```
//! # use neuroim::{DenseNeuroVol, bilateral_filter};
//! # use ndarray::Array3;
//! # use neuroim::NeuroSpace;
//! # use neuroim::error::Result;
//! # fn main() -> Result<()> {
//! # let space = NeuroSpace::new(vec![10, 10, 10], None, None, None, None)?;
//! # let data = Array3::from_elem((10, 10, 10), 1.0f32);
//! # let volume = DenseNeuroVol::new(data, space)?;
//! // Apply edge-preserving bilateral filter
//! let spatial_sigma = 2.0;  // Spatial standard deviation
//! let range_sigma = 10.0;   // Intensity range standard deviation
//! let filtered = bilateral_filter(&volume, spatial_sigma, range_sigma)?;
//! # Ok(())
//! # }
//! ```

use ndarray::{Array3, Axis, s};
use std::cmp::{max, min};
use std::iter::Sum;

use crate::error::{Error, Result};
use crate::kernel::{gaussian_kernel, Kernel};
use crate::neuro_vol::{NeuroVol, DenseNeuroVol, LogicalNeuroVol};
use crate::neuro_vec::{NeuroVecTrait, DenseNeuroVec};
use crate::numeric::{Numeric, AsFloat};

/// Apply Gaussian blur to a volume
///
/// # Arguments
/// * `vol` - Input volume to blur
/// * `sigma` - Standard deviation of the Gaussian in real-world units
/// * `window` - Window multiplier for kernel size (kernel size = 2*window*sigma + 1)
/// * `mask` - Optional mask to restrict filtering
pub fn gaussian_blur<T: Numeric>(
    vol: &DenseNeuroVol<T>,
    sigma: f64,
    window: f64,
    mask: Option<&LogicalNeuroVol>,
) -> Result<DenseNeuroVol<T>> {
    if window <= 0.0 {
        return Err(Error::InvalidParameter("Window must be positive".to_string()));
    }

    if sigma <= 0.0 {
        return Err(Error::InvalidParameter("Sigma must be positive".to_string()));
    }

    // Get voxel dimensions
    let spacing = &vol.space().spacing;

