//! Spatial filtering examples

use neuroim::{
    read_nifti, write_nifti, 
    gaussian_blur, bilateral_filter, guided_filter,
    NeuroVol, DenseNeuroVol
};
use neuroim::error::Result;

fn main() -> Result<()> {
    // Read input volume
    println!("Reading input volume...");
    let volume = read_nifti::<f32>("data/brain.nii.gz")?;

    // Example 1: Gaussian smoothing with different sigma values
    println!("\n1. Gaussian smoothing with different sigma values...");
    let sigmas = vec![2.0, 4.0, 6.0];

    for sigma in sigmas {
        println!("   Applying Gaussian blur with sigma = {}mm...", sigma);
        let gaussian_smoothed = gaussian_blur(&volume, sigma, 3.0, None)?;
        let filename = format!("examples/data/brain_gaussian_{:.0}mm.nii.gz", sigma);
        write_nifti(&filename, &gaussian_smoothed)?;
        println!("     Saved {}", filename);
    }

    // Example 2: Bilateral filter (edge-preserving)
    println!("\n2. Bilateral filter (edge-preserving)...");
    let spatial_sigma = 3.0;  // Spatial extent
    let range_sigma = 20.0;   // Intensity similarity
    let bilateral_filtered = bilateral_filter(&volume, spatial_sigma, range_sigma)?;
    write_nifti("examples/data/brain_bilateral.nii.gz", &bilateral_filtered)?;
    println!("   Saved brain_bilateral.nii.gz");

    // Example 3: Guided filter
    println!("\n3. Guided filter (using same image as guide)...");
    let radius = 5.0;
    let guided_filtered = guided_filter(&volume, &volume, radius)?;
    write_nifti("examples/data/brain_guided.nii.gz", &guided_filtered)?;
    println!("   Saved brain_guided.nii.gz");

    // Example 4: Multi-scale smoothing comparison
    println!("\n4. Multi-scale smoothing comparison...");
    let scales = vec![1.0, 2.0, 4.0, 8.0];
    for scale in scales {
        let smoothed = gaussian_blur(&volume, scale, 3.0, None)?;
        let filename = format!("examples/data/brain_scale_{:.0}mm.nii.gz", scale);
        write_nifti(&filename, &smoothed)?;
        println!("   Saved {}", filename);
    }

    // Example 5: Effect of window size parameter
    println!("\n5. Effect of different window sizes...");
    let sigma = 3.0;
    let windows = vec![2.0, 3.0, 4.0];

    for window in windows {
        println!("   Applying Gaussian blur with window = {}...", window);
        let smoothed = gaussian_blur(&volume, sigma, window, None)?;
        let filename = format!("examples/data/brain_window_{:.0}.nii.gz", window);
        write_nifti(&filename, &smoothed)?;
        println!("     Saved {}", filename);
    }

    // Example 6: Filtering with mask
    println!("\n6. Filtering with brain mask...");

    // Create brain mask
    let threshold = 100.0;
    let mask_data = volume.as_dense()?.data.mapv(|v| v > threshold);
    let mask = neuroim::LogicalNeuroVol::new(mask_data, volume.space().clone())?;

    println!("   Brain mask contains {} voxels", 
             mask.data.iter().filter(|&&v| v).count());

    // Apply Gaussian smoothing with mask
    let masked_smoothed = gaussian_blur(&volume, 4.0, 3.0, Some(&mask))?;
    write_nifti("examples/data/brain_masked_smooth.nii.gz", &masked_smoothed)?;
    println!("   Saved brain_masked_smooth.nii.gz");

    // Example 7: Compare different bilateral filter parameters
    println!("\n7. Bilateral filter parameter comparison...");

    let bilateral_configs = vec![
        (2.0, 10.0, "conservative"),
        (3.0, 20.0, "balanced"),
        (4.0, 30.0, "aggressive"),
    ];

    for (spatial_sigma, range_sigma, name) in bilateral_configs {
        println!("   Bilateral filter: {} (spatial={}, range={})", name, spatial_sigma, range_sigma);
        let filtered = bilateral_filter(&volume, spatial_sigma, range_sigma)?;
        let filename = format!("examples/data/brain_bilateral_{}.nii.gz", name);
        write_nifti(&filename, &filtered)?;
        println!("     Saved {}", filename);
    }

    // Example 8: Quantitative comparison of filters
    println!("\n8. Quantitative comparison of filters...");

    // Calculate statistics for different filters
    let original_stats = calculate_volume_stats(&volume)?;
    println!("   Original volume: mean={:.2}, std={:.2}", original_stats.0, original_stats.1);

    let gaussian_smoothed = gaussian_blur(&volume, 3.0, 3.0, None)?;
    let gaussian_stats = calculate_volume_stats(&gaussian_smoothed)?;
    println!("   Gaussian smoothed: mean={:.2}, std={:.2}", gaussian_stats.0, gaussian_stats.1);

    let bilateral_smoothed = bilateral_filter(&volume, 3.0, 20.0)?;
    let bilateral_stats = calculate_volume_stats(&bilateral_smoothed)?;
    println!("   Bilateral filtered: mean={:.2}, std={:.2}", bilateral_stats.0, bilateral_stats.1);

    let guided_smoothed = guided_filter(&volume, &volume, 5.0)?;
    let guided_stats = calculate_volume_stats(&guided_smoothed)?;
    println!("   Guided filtered: mean={:.2}, std={:.2}", guided_stats.0, guided_stats.1);

    // Save comparison summary
    let summary = format!(
        "Filtering Comparison Summary\n\
         ============================\n\
         \n\
         Original volume:\n\
         - Mean: {:.2}\n\
         - Std: {:.2}\n\
         \n\
         Gaussian smoothed (sigma=3mm):\n\
         - Mean: {:.2}\n\
         - Std: {:.2}\n\
         \n\
         Bilateral filtered (spatial=3, range=20):\n\
         - Mean: {:.2}\n\
         - Std: {:.2}\n\
         \n\
         Guided filtered (radius=5):\n\
         - Mean: {:.2}\n\
         - Std: {:.2}\n\
         \n\
         Files generated:\n\
         - Gaussian smoothed at multiple scales\n\
         - Bilateral filtered with different parameters\n\
         - Guided filtered\n\
         - Window size comparison\n\
         - Masked filtering results\n",
        original_stats.0, original_stats.1,
        gaussian_stats.0, gaussian_stats.1,
        bilateral_stats.0, bilateral_stats.1,
        guided_stats.0, guided_stats.1
    );

    std::fs::write("examples/data/filtering_summary.txt", summary)?;
    println!("\n   Summary saved to examples/data/filtering_summary.txt");

    println!("\nFiltering complete!");

    Ok(())
}

fn calculate_volume_stats(volume: &DenseNeuroVol<f32>) -> Result<(f32, f32)> {
    let data = volume.as_dense()?.data.as_slice().unwrap();
    let mean = data.iter().sum::<f32>() / data.len() as f32;
    let variance = data.iter()
        .map(|&x| (x - mean).powi(2))
        .sum::<f32>() / data.len() as f32;
    let std = variance.sqrt();
    Ok((mean, std))
}

