//! I/O functions for neuroimaging data
//!
//! This module provides functions for reading and writing neuroimaging files,
//! with support for NIfTI format.

use std::path::Path;
use std::iter::Sum;

use nifti::{NiftiObject, NiftiHeader, ReaderOptions, IntoNdArray, writer::WriterOptions};
use ndarray::{Array3};
use nalgebra::Matrix4;

use crate::error::{Error, Result};
use crate::neuro_space::NeuroSpace;
use crate::neuro_vol::{DenseNeuroVol, NeuroVol};
use crate::neuro_vec::{DenseNeuroVec, NeuroVecTrait};
use crate::axis::{find_anatomy_3d, AnyAxisSet};
use crate::numeric::Numeric;

/// Read a 3D neuroimaging volume from file with automatic type conversion to f64
///
/// # Arguments
/// * `filename` - Path to the neuroimaging file
/// * `index` - For 4D files, which 3D volume to extract (0-based)
///
/// # Returns
/// A `DenseNeuroVol<f64>` containing the loaded volume
pub fn read_vol(filename: impl AsRef<Path>, index: usize) -> Result<DenseNeuroVol<f64>> {
    read_vol_as::<f64>(filename, index)
}

