                            visited[[cx, cy, cz]] = true;
                            temp_visited.push((cx, cy, cz));
                            cluster_size += 1;

                            for &(dx, dy, dz) in &neighbors_6 {
                                let nx = cx as i32 + dx;
                                let ny = cy as i32 + dy;
                                let nz = cz as i32 + dz;

                                if nx >= 0 && ny >= 0 && nz >= 0 {
                                    let (ux, uy, uz) = (nx as usize, ny as usize, nz as usize);
                                    if ux < dims[0] && uy < dims[1] && uz < dims[2] {
