/// Write a neuroimaging vector to file
pub fn write_vec(
    vec: &DenseNeuroVec<f32>,
    filename: impl AsRef<Path>,
) -> Result<()> {
    let path = filename.as_ref();

    // Create a mutable header based on the vector
    let mut header = NiftiHeader::default();

    // Set dimensions
    let shape = vec.shape();
    header.dim[0] = 4; // 4D volume
    header.dim[1] = shape.0 as u16;
    header.dim[2] = shape.1 as u16;
    header.dim[3] = shape.2 as u16;
    header.dim[4] = shape.3 as u16;

    // Set voxel dimensions
    let spacing = vec.spacing();
    header.pixdim[1] = spacing[0] as f32;
    header.pixdim[2] = spacing[1] as f32;
    header.pixdim[3] = spacing[2] as f32;
    if spacing.len() > 3 {
        header.pixdim[4] = spacing[3] as f32;
    }

    // Set data type
    header.datatype = 16; // NIFTI_TYPE_FLOAT32
    header.bitpix = 32;

    // Set sform matrix if available
    if space_has_valid_transform(&vec.space) {
        header.sform_code = 2; // NIFTI_XFORM_SCANNER_ANAT

        // Set the sform matrix values directly
        let trans = &vec.space.trans;
        if trans.nrows() >= 4 && trans.ncols() >= 4 {
            header.srow_x = [trans[(0,0)] as f32, trans[(0,1)] as f32, trans[(0,2)] as f32, trans[(0,3)] as f32];
            header.srow_y = [trans[(1,0)] as f32, trans[(1,1)] as f32, trans[(1,2)] as f32, trans[(1,3)] as f32];
            header.srow_z = [trans[(2,0)] as f32, trans[(2,1)] as f32, trans[(2,2)] as f32, trans[(2,3)] as f32];
        }

