//! Spatial filtering examples

use neuroim::{
    gaussian_blur, bilateral_filter, guided_filter,
    NeuroVol, DenseNeuroVol
};
use neuroim::io::{read_vol_f32, write_vol};
use neuroim::error::Result;

fn main() -> Result<()> {
    // Create synthetic brain volume
    println!("Creating synthetic brain volume...");
    let space = neuroim::NeuroSpace::new(vec![32, 32, 32], None, None, None, None)?;
    let mut data = ndarray::Array3::<f32>::zeros((32, 32, 32));

    // Create a synthetic brain with noise (smaller for faster processing)
    for x in 0..32 {
        for y in 0..32 {
            for z in 0..32 {
                let cx = (x as f32 - 16.0) / 10.0;
                let cy = (y as f32 - 16.0) / 10.0;
                let cz = (z as f32 - 16.0) / 12.0;
                let r2 = cx*cx + cy*cy + cz*cz;
                if r2 < 1.0 {
                    // Add some noise
                    let noise = (x * 7 + y * 13 + z * 17) % 20;
                    data[[x, y, z]] = 200.0 * (1.0 - r2) + noise as f32;
                }
            }
        }
    }

    let volume = DenseNeuroVol::new(data, space)?;

    // Example 1: Simple Gaussian smoothing
    println!("\n1. Gaussian smoothing...");
    let sigma = 2.0;

    println!("   Applying Gaussian blur with sigma = {}mm...", sigma);
    let gaussian_smoothed = gaussian_blur(&volume, sigma, 2.0, None)?;
    let filename = "examples/data/brain_gaussian.nii.gz";
    write_vol(&gaussian_smoothed, filename)?;
    println!("     Saved {}", filename);

    // Example 2: Bilateral filter (edge-preserving)
    println!("\n2. Bilateral filter (edge-preserving)...");
    let spatial_sigma = 2.0;  // Spatial extent
    let range_sigma = 20.0;   // Intensity similarity
    let bilateral_filtered = bilateral_filter(&volume, spatial_sigma, range_sigma, 2.0, None)?;
    write_vol(&bilateral_filtered, "examples/data/brain_bilateral.nii.gz")?;
    println!("   Saved brain_bilateral.nii.gz");

    // Example 3: Guided filter
    println!("\n3. Guided filter...");
    let guided_filtered = guided_filter(&volume, 3, 0.01)?;
    write_vol(&guided_filtered, "examples/data/brain_guided.nii.gz")?;
    println!("   Saved brain_guided.nii.gz");

    // Calculate simple statistics
    println!("\n4. Volume statistics...");
    let original_stats = calculate_volume_stats(&volume)?;
    println!("   Original volume: mean={:.2}, std={:.2}", original_stats.0, original_stats.1);

    let gaussian_stats = calculate_volume_stats(&gaussian_smoothed)?;
    println!("   Gaussian smoothed: mean={:.2}, std={:.2}", gaussian_stats.0, gaussian_stats.1);

    println!("\nFiltering complete!");

    Ok(())
}

fn calculate_volume_stats(volume: &DenseNeuroVol<f32>) -> Result<(f32, f32)> {
    let dense = volume.as_dense()?;
    let data = dense.data.as_slice().unwrap();
    let mean = data.iter().sum::<f32>() / data.len() as f32;
    let variance = data.iter()
        .map(|&x| (x - mean).powi(2))
        .sum::<f32>() / data.len() as f32;
    let std = variance.sqrt();
    Ok((mean, std))
}

