//! Searchlight analysis for multivariate pattern analysis (MVPA)

use neuroim::{
    NeuroVol, LogicalNeuroVol, DenseNeuroVol,
    spherical_roi, ROI
};
use neuroim::io::{read_vol_f32, write_vol};
use neuroim::error::Result;
use ndarray::Array3;
use rand;

fn main() -> Result<()> {
    println!("=== Searchlight Analysis Demo ===\n");

    // Create synthetic brain volume
    println!("1. Creating synthetic brain volume...");
    let space = neuroim::NeuroSpace::new(vec![32, 32, 32], None, None, None, None)?;
    let mut data = Array3::<f32>::zeros((32, 32, 32));

    // Create a synthetic brain
    for x in 0..32 {
        for y in 0..32 {
            for z in 0..32 {
                let cx = (x as f32 - 16.0) / 10.0;
                let cy = (y as f32 - 16.0) / 10.0;
                let cz = (z as f32 - 16.0) / 12.0;
                let r2 = cx*cx + cy*cy + cz*cz;
                if r2 < 1.0 {
                    data[[x, y, z]] = 200.0 * (1.0 - r2);
                }
            }
        }
    }

    let brain = DenseNeuroVol::new(data.clone(), space.clone())?;

    // Create a brain mask
    println!("2. Creating brain mask...");
    let threshold = 100.0;
    let mask_data = brain.as_dense()?.data.mapv(|v| v > threshold);
    let mask = LogicalNeuroVol::new(mask_data, brain.space().clone())?;

    println!("   Brain mask contains {} voxels", mask.data.iter().filter(|&&v| v).count());

    // Create simulated activation data
    println!("\n3. Creating simulated activation data...");

    // Add some activation patterns
    let mut activation_data = data.clone();
    // Add activation in region 1
    for x in 10..20 {
        for y in 10..20 {
            for z in 10..20 {
                if data[[x, y, z]] > 100.0 {
                    activation_data[[x, y, z]] += 50.0;
                }
            }
        }
    }

    let activation_volume = DenseNeuroVol::new(activation_data, space)?;

    // Example searchlight analysis
    println!("\n4. Running simple searchlight analysis...");
    let radius = 4.0; // 4mm radius searchlights

    // Initialize accuracy map
    let dims = brain.space().dim.clone();
    let mut accuracy_map = Array3::<f32>::zeros((dims[0], dims[1], dims[2]));

    // Sample searchlight locations (every 3rd voxel to speed up demo)
    let mut searchlight_count = 0;
    for x in (5..dims[0]-5).step_by(3) {
        for y in (5..dims[1]-5).step_by(3) {
            for z in (5..dims[2]-5).step_by(3) {
                // Check if center is in mask
                if !mask.data[[x, y, z]] {
                    continue;
                }

                // Create spherical ROI
                let center = [x as i32, y as i32, z as i32];
                if let Ok(roi) = spherical_roi::<f32>(&mask, &center, radius, Some(1.0), true) {
                    if roi.size() < 5 { // Skip very small searchlights
                        continue;
                    }

                    // Mock accuracy based on mean activation in ROI
                    let mut sum = 0.0;
                    let mut count = 0;
                    for idx in roi.coords.indices() {
                        if let Some(val) = activation_volume.data.as_slice().unwrap().get(idx) {
                            sum += val;
                            count += 1;
                        }
                    }

                    let accuracy = if count > 0 {
                        (sum / count as f32 / 200.0).min(1.0).max(0.5)
                    } else {
                        0.5
                    };

                    accuracy_map[[x, y, z]] = accuracy;
                    searchlight_count += 1;
                }
            }
        }
    }

    println!("   Completed {} searchlights", searchlight_count);

    // Save searchlight accuracy map
    let accuracy_volume = DenseNeuroVol::new(accuracy_map.clone(), brain.space().clone())?;
    write_vol(&accuracy_volume, "examples/data/searchlight_accuracy_simple.nii.gz")?;
    println!("   Saved accuracy map to examples/data/searchlight_accuracy_simple.nii.gz");

    // Print summary statistics
    let acc_values: Vec<f32> = accuracy_map.iter()
        .filter(|&&v| v > 0.0)
        .copied()
        .collect();

    if !acc_values.is_empty() {
        let mean_acc = acc_values.iter().sum::<f32>() / acc_values.len() as f32;
        let max_acc = acc_values.iter().fold(f32::NEG_INFINITY, |a, &b| a.max(b));
        println!("   Mean accuracy: {:.3}", mean_acc);
        println!("   Max accuracy: {:.3}", max_acc);
    }

    println!("\n=== Searchlight Analysis Complete! ===");

    Ok(())
}

