//! Connected components and spatial clustering analysis

use neuroim::{
    NeuroVol, LogicalNeuroVol, DenseNeuroVol
};
use neuroim::io::{read_vol_f32, write_vol};
use neuroim::error::Result;
use ndarray::Array3;

fn main() -> Result<()> {
    println!("=== Connected Components & Clustering Demo ===\n");

    // Create synthetic brain volume
    println!("1. Creating synthetic brain volume...");
    let space = neuroim::NeuroSpace::new(vec![32, 32, 32], None, None, None, None)?;
    let mut data = Array3::<f32>::zeros((32, 32, 32));

    // Create a synthetic brain
    for x in 0..32 {
        for y in 0..32 {
            for z in 0..32 {
                let cx = (x as f32 - 16.0) / 10.0;
                let cy = (y as f32 - 16.0) / 10.0;
                let cz = (z as f32 - 16.0) / 12.0;
                let r2 = cx*cx + cy*cy + cz*cz;
                if r2 < 1.0 {
                    data[[x, y, z]] = 200.0 * (1.0 - r2);
                }
            }
        }
    }

    let brain = DenseNeuroVol::new(data.clone(), space.clone())?;

    // Create brain mask
    let threshold = 100.0;
    let mask_data = brain.as_dense()?.data.mapv(|v| v > threshold);
    let brain_mask = LogicalNeuroVol::new(mask_data, brain.space().clone())?;

    println!("   Brain mask contains {} voxels", 
             brain_mask.data.iter().filter(|&&v| v).count());

    // Example 1: Create synthetic activation map with multiple clusters
    println!("\n2. Creating synthetic activation map with clusters...");

    let dims = brain.space().dim.clone();
    let mut activation_data = Array3::<f32>::zeros((dims[0], dims[1], dims[2]));

    // Define cluster centers (smaller for 32x32x32 volume)
    let cluster_centers = vec![
        ((10, 16, 16), 3.0, 120.0),   // Left cluster
        ((22, 16, 16), 3.0, 110.0),   // Right cluster  
        ((16, 10, 16), 2.5, 100.0),   // Front cluster
        ((16, 22, 16), 2.0, 90.0),    // Back cluster
    ];

    // Create Gaussian-like clusters
    for &((cx, cy, cz), radius, intensity) in &cluster_centers {
        for x in 0..dims[0] {
            for y in 0..dims[1] {
                for z in 0..dims[2] {
                    let dx = x as f32 - cx as f32;
                    let dy = y as f32 - cy as f32;
                    let dz = z as f32 - cz as f32;
                    let distance = (dx*dx + dy*dy + dz*dz).sqrt();

                    if distance <= radius {
                        let gaussian = intensity * (-0.5 * (distance / (radius/3.0)).powi(2)).exp();
                        activation_data[[x, y, z]] = activation_data[[x, y, z]].max(gaussian);
                    }
                }
            }
        }
    }

    // Apply brain mask to activation
    for x in 0..dims[0] {
        for y in 0..dims[1] {
            for z in 0..dims[2] {
                if !brain_mask.data[[x, y, z]] {
                    activation_data[[x, y, z]] = 0.0;
                }
            }
        }
    }

    let activation_volume = DenseNeuroVol::new(activation_data, brain.space().clone())?;
    write_vol(&activation_volume, "examples/data/synthetic_activation_small.nii.gz")?;
    println!("   Created synthetic activation map with {} clusters", cluster_centers.len());

    // Example 2: Simple connected components at a threshold
    println!("\n3. Finding connected components at threshold 80...");

    let thresh = 80.0;

    // Create binary mask at threshold
    let thresholded_data = activation_volume.data.mapv(|v| v > thresh);
    let thresholded_mask = LogicalNeuroVol::new(thresholded_data, brain.space().clone())?;

    // Simple connected components using flood fill
    let mut visited = Array3::<bool>::from_elem((dims[0], dims[1], dims[2]), false);
    let mut cluster_map = Array3::<i32>::zeros((dims[0], dims[1], dims[2]));
    let mut cluster_id = 1;
    let mut cluster_sizes = Vec::new();

    // 6-connected neighbors (face connectivity)
    let neighbors = vec![
        (-1, 0, 0), (1, 0, 0),   // x-axis
        (0, -1, 0), (0, 1, 0),   // y-axis  
        (0, 0, -1), (0, 0, 1),   // z-axis
    ];

    for x in 0..dims[0] {
        for y in 0..dims[1] {
            for z in 0..dims[2] {
                if thresholded_mask.data[[x, y, z]] && !visited[[x, y, z]] {
                    // Start new cluster - flood fill
                    let mut stack = vec![(x, y, z)];
                    let mut cluster_size = 0;

                    while let Some((cx, cy, cz)) = stack.pop() {
                        if cx >= dims[0] || cy >= dims[1] || cz >= dims[2] {
                            continue;
                        }
                        if visited[[cx, cy, cz]] || !thresholded_mask.data[[cx, cy, cz]] {
                            continue;
                        }

                        visited[[cx, cy, cz]] = true;
                        cluster_map[[cx, cy, cz]] = cluster_id;
                        cluster_size += 1;

                        // Add neighbors to stack
                        for &(dx, dy, dz) in &neighbors {
                            let nx = cx as i32 + dx;
                            let ny = cy as i32 + dy;
                            let nz = cz as i32 + dz;

                            if nx >= 0 && ny >= 0 && nz >= 0 {
                                let (ux, uy, uz) = (nx as usize, ny as usize, nz as usize);
                                if ux < dims[0] && uy < dims[1] && uz < dims[2] {
                                    stack.push((ux, uy, uz));
                                }
                            }
                        }
                    }

                    if cluster_size >= 3 { // Minimum cluster size
                        cluster_sizes.push((cluster_id, cluster_size));
                        cluster_id += 1;
                    } else {
                        // Remove small cluster
                        for x2 in 0..dims[0] {
                            for y2 in 0..dims[1] {
                                for z2 in 0..dims[2] {
                                    if cluster_map[[x2, y2, z2]] == cluster_id - 1 {
                                        cluster_map[[x2, y2, z2]] = 0;
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    let n_clusters = cluster_id - 1;
    println!("   Found {} clusters", n_clusters);

    // Save cluster map
    let cluster_f32_data = cluster_map.mapv(|v| v as f32);
    let cluster_volume = DenseNeuroVol::new(cluster_f32_data, brain.space().clone())?;
    write_vol(&cluster_volume, "examples/data/clusters_simple.nii.gz")?;

    // Print cluster sizes
    for (id, size) in &cluster_sizes {
        println!("   Cluster {}: {} voxels", id, size);
    }

    // Save analysis summary
    println!("\n4. Saving analysis summary...");

    let summary = format!(
        "Connected Components Analysis Summary\n\
         ====================================\n\
         \n\
         Synthetic data:\n\
         - Created {} synthetic clusters\n\
         - Brain volume dimensions: {:?}\n\
         - Brain mask voxels: {}\n\
         \n\
         Connected components at threshold {}:\n\
         - Found {} clusters\n\
         - Cluster sizes: {:?}\n\
         \n\
         Files generated:\n\
         - synthetic_activation_small.nii.gz: Activation map\n\
         - clusters_simple.nii.gz: Cluster label map\n",
        cluster_centers.len(),
        dims,
        brain_mask.data.iter().filter(|&&v| v).count(),
        thresh,
        n_clusters,
        cluster_sizes
    );

    std::fs::write("examples/data/clustering_simple_report.txt", summary)?;
    println!("   Analysis report saved to examples/data/clustering_simple_report.txt");

    println!("\n=== Connected Components Analysis Complete! ===");

    Ok(())
}

