    }

    let activation_volume = DenseNeuroVol::new(activation_data, brain.space().clone())?;
    write_vol(&activation_volume, "examples/data/synthetic_activation_small.nii.gz")?;
    println!("   Created synthetic activation map with {} clusters", cluster_centers.len());

    // Example 2: Simple connected components at a threshold
    println!("\n3. Finding connected components at threshold 80...");

    let thresh = 80.0;

    // Create binary mask at threshold
    let thresholded_data = activation_volume.data.mapv(|v| v > thresh);
    let thresholded_mask = LogicalNeuroVol::new(thresholded_data, brain.space().clone())?;

    // Simple connected components using flood fill
    let mut visited = Array3::<bool>::from_elem((dims[0], dims[1], dims[2]), false);
    let mut cluster_map = Array3::<i32>::zeros((dims[0], dims[1], dims[2]));
    let mut cluster_id = 1;
    let mut cluster_sizes = Vec::new();

    // 6-connected neighbors (face connectivity)
    let neighbors = vec![
        (-1, 0, 0), (1, 0, 0),   // x-axis
        (0, -1, 0), (0, 1, 0),   // y-axis  
        (0, 0, -1), (0, 0, 1),   // z-axis
    ];

    for x in 0..dims[0] {
        for y in 0..dims[1] {
            for z in 0..dims[2] {
                if thresholded_mask.data[[x, y, z]] && !visited[[x, y, z]] {
                    // Start new cluster - flood fill
                    let mut stack = vec![(x, y, z)];
                    let mut cluster_size = 0;

                    while let Some((cx, cy, cz)) = stack.pop() {
                        if cx >= dims[0] || cy >= dims[1] || cz >= dims[2] {
                            continue;
                        }
                        if visited[[cx, cy, cz]] || !thresholded_mask.data[[cx, cy, cz]] {
                            continue;
                        }

                        visited[[cx, cy, cz]] = true;
                        cluster_map[[cx, cy, cz]] = cluster_id;
                        cluster_size += 1;

                        // Add neighbors to stack
                        for &(dx, dy, dz) in &neighbors {
                            let nx = cx as i32 + dx;
                            let ny = cy as i32 + dy;
                            let nz = cz as i32 + dz;

                            if nx >= 0 && ny >= 0 && nz >= 0 {
                                let (ux, uy, uz) = (nx as usize, ny as usize, nz as usize);
                                if ux < dims[0] && uy < dims[1] && uz < dims[2] {
                                    stack.push((ux, uy, uz));
                                }
                            }
                        }
                    }

                    if cluster_size >= 3 { // Minimum cluster size
                        cluster_sizes.push((cluster_id, cluster_size));
                        cluster_id += 1;
                    } else {
                        // Remove small cluster
                        for x2 in 0..dims[0] {
                            for y2 in 0..dims[1] {
                                for z2 in 0..dims[2] {
                                    if cluster_map[[x2, y2, z2]] == cluster_id - 1 {
                                        cluster_map[[x2, y2, z2]] = 0;
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    let n_clusters = cluster_id - 1;
    println!("   Found {} clusters", n_clusters);

    // Save cluster map
    let cluster_f32_data = cluster_map.mapv(|v| v as f32);
    let cluster_volume = DenseNeuroVol::new(cluster_f32_data, brain.space().clone())?;
    write_vol(&cluster_volume, "examples/data/clusters_simple.nii.gz")?;

    // Print cluster sizes
    for (id, size) in &cluster_sizes {
        println!("   Cluster {}: {} voxels", id, size);
    }

    // Save analysis summary
    println!("\n4. Saving analysis summary...");

    let summary = format!(
        "Connected Components Analysis Summary\n\
         ====================================\n\
         \n\
         Synthetic data:\n\
         - Created {} synthetic clusters\n\
         - Brain volume dimensions: {:?}\n\
         - Brain mask voxels: {}\n\
         \n\
         Connected components at threshold {}:\n\
         - Found {} clusters\n\
         - Cluster sizes: {:?}\n\
         \n\
         Files generated:\n\
         - synthetic_activation_small.nii.gz: Activation map\n\
         - clusters_simple.nii.gz: Cluster label map\n",
        cluster_centers.len(),
        dims,
        brain_mask.data.iter().filter(|&&v| v).count(),
        thresh,
        n_clusters,
        cluster_sizes
    );

    std::fs::write("examples/data/clustering_simple_report.txt", summary)?;
    println!("   Analysis report saved to examples/data/clustering_simple_report.txt");

    println!("\n=== Connected Components Analysis Complete! ===");

    Ok(())
}
